		if entry.Branch == "" {
			return m, m.handleError(fmt.Errorf("plan has no branch to merge"))
		}
		planName := taskstate.DisplayName(planFile)
		mergeAction := func() tea.Msg {
			// Kill all instances bound to this plan.
			for i := len(m.allInstances) - 1; i >= 0; i-- {
