		plannerPrompted:       make(map[string]bool),
		coderPushPrompted:     make(map[string]bool),
	}

	msg := metadataResultMsg{
		Results: []instanceMetadata{
			{Title: reviewerInst.Title, TmuxAlive: false},
		},
