			if err != nil {
				return err
			}
			if err := executePlanRegister(plansDir, args[0], branchFlag, topicFlag, descriptionFlag, resolveStore(plansDir)); err != nil {
				return err
			}
			fmt.Printf("registered: %s → ready\n", args[0])
			return nil
		},
	}
