package taskfsm

import (
	"fmt"

	"github.com/kastheco/kasmos/config/taskstate"
	"github.com/kastheco/kasmos/config/taskstore"
)

// Status represents the lifecycle state of a plan.
type Status string

const (
	StatusReady        Status = "ready"
	StatusPlanning     Status = "planning"
	StatusImplementing Status = "implementing"
	StatusReviewing    Status = "reviewing"
	StatusDone         Status = "done"
	StatusCancelled    Status = "cancelled"
)

// Event represents a lifecycle transition trigger.
type Event string

const (
	PlanStart              Event = "plan_start"
	PlannerFinished        Event = "planner_finished"
	ImplementStart         Event = "implement_start"
	ImplementFinished      Event = "implement_finished"
	ReviewApproved         Event = "review_approved"
	ReviewChangesRequested Event = "review_changes_requested"
	RequestReview          Event = "request_review"
	StartOver              Event = "start_over"
	Reimplement            Event = "reimplement"
	Cancel                 Event = "cancel"
	Reopen                 Event = "reopen"
)

// IsUserOnly returns true if this event can only be triggered from the TUI,
// never by agent sentinel files.
func (e Event) IsUserOnly() bool {
	switch e {
	case StartOver, Reimplement, RequestReview, Cancel, Reopen:
		return true
	}
	return false
}

// transitionTable defines all valid state transitions.
// Key: current status → event → new status.
var transitionTable = map[Status]map[Event]Status{
	StatusReady: {
		PlanStart:      StatusPlanning,
		ImplementStart: StatusImplementing,
		Cancel:         StatusCancelled,
	},
	StatusPlanning: {
		PlanStart:       StatusPlanning, // allow restart after crash/interrupt
		PlannerFinished: StatusReady,
		Cancel:          StatusCancelled,
	},
	StatusImplementing: {
		ImplementFinished: StatusReviewing,
		Cancel:            StatusCancelled,
	},
	StatusReviewing: {
		ReviewApproved:         StatusDone,
		ReviewChangesRequested: StatusImplementing,
		Cancel:                 StatusCancelled,
	},
	StatusDone: {
		StartOver:     StatusPlanning,
		Reimplement:   StatusImplementing, // resume implementation without resetting branch
		RequestReview: StatusReviewing,    // retrigger review for unmerged branches
		Cancel:        StatusCancelled,    // explicit user cancellation from done
	},
	StatusCancelled: {
		Reopen: StatusPlanning,
	},
}

// ApplyTransition returns the new status for the given current status and event.
// Returns an error if the transition is not valid.
func ApplyTransition(current Status, event Event) (Status, error) {
	events, ok := transitionTable[current]
	if !ok {
		return "", fmt.Errorf("no transitions defined for status %q", current)
	}
	next, ok := events[event]
	if !ok {
		return "", fmt.Errorf("invalid transition: %q + %q", current, event)
	}
	return next, nil
}

// TaskStateMachine is the sole writer of plan state. All plan status mutations
// must flow through Transition(). The store handles concurrency via SQLite.
type TaskStateMachine struct {
	dir     string          // docs/plans/ directory (for file operations)
	store   taskstore.Store // always non-nil
	project string          // project name used with the store
}

// New creates a TaskStateMachine backed by the given store.
func New(store taskstore.Store, project, dir string) *TaskStateMachine {
	return &TaskStateMachine{dir: dir, store: store, project: project}
}

// Transition applies an event to a plan's current status. It reads the current
// state from the store, validates the transition, writes the new state, and returns.
// Concurrency is handled server-side via SQLite's own locking.
func (m *TaskStateMachine) Transition(planFile string, event Event) error {
	ps, err := taskstate.Load(m.store, m.project, m.dir)
	if err != nil {
		return fmt.Errorf("load plan state: %w", err)
	}
	entry, ok := ps.Entry(planFile)
	if !ok {
		return fmt.Errorf("plan not found: %s", planFile)
	}
	currentStatus := mapLegacyStatus(entry.Status)
	newStatus, err := ApplyTransition(currentStatus, event)
	if err != nil {
		return err
	}
	// ForceSetStatus writes through to the store.
	return ps.ForceSetStatus(planFile, taskstate.Status(newStatus))
}

// mapLegacyStatus converts old planstate statuses to FSM statuses.
// Handles the consolidated aliases (in_progress → implementing, completed/finished → done).
func mapLegacyStatus(s taskstate.Status) Status {
	switch s {
	case "in_progress":
		return StatusImplementing
	case "completed", "finished":
		return StatusDone
	default:
		return Status(s)
	}
}

package taskfsm

import (
	"testing"
	"time"

	"github.com/kastheco/kasmos/config/taskstate"
	"github.com/kastheco/kasmos/config/taskstore"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// newTestFSM creates a TaskStateMachine backed by an in-memory SQLite store.
func newTestFSM(t *testing.T) (*TaskStateMachine, taskstore.Store) {
	t.Helper()
	store := taskstore.NewTestSQLiteStore(t)
	fsm := New(store, "test-proj", t.TempDir())
	return fsm, store
}

func TestTransition_ValidTransitions(t *testing.T) {
	cases := []struct {
		from  Status
		event Event
		to    Status
	}{
		{StatusReady, PlanStart, StatusPlanning},
		{StatusPlanning, PlanStart, StatusPlanning}, // restart after crash/interrupt
		{StatusPlanning, PlannerFinished, StatusReady},
		{StatusReady, ImplementStart, StatusImplementing},
		{StatusImplementing, ImplementFinished, StatusReviewing},
		{StatusReviewing, ReviewApproved, StatusDone},
		{StatusReviewing, ReviewChangesRequested, StatusImplementing},
		{StatusDone, StartOver, StatusPlanning},
		{StatusDone, Cancel, StatusCancelled},
		{StatusReady, Cancel, StatusCancelled},
		{StatusPlanning, Cancel, StatusCancelled},
		{StatusImplementing, Cancel, StatusCancelled},
		{StatusReviewing, Cancel, StatusCancelled},
		{StatusCancelled, Reopen, StatusPlanning},
	}
	for _, tc := range cases {
		t.Run(string(tc.from)+"_"+string(tc.event), func(t *testing.T) {
			result, err := ApplyTransition(tc.from, tc.event)
			require.NoError(t, err)
			assert.Equal(t, tc.to, result)
		})
	}
}

func TestTransition_InvalidTransitions(t *testing.T) {
	cases := []struct {
		from  Status
		event Event
	}{
		{StatusReady, PlannerFinished},    // not planning
		{StatusReady, ImplementFinished},  // not implementing
		{StatusReady, ReviewApproved},     // not reviewing
		{StatusPlanning, ImplementStart},  // must go through ready
		{StatusImplementing, PlanStart},   // can't go backwards
		{StatusDone, PlanStart},           // terminal
		{StatusDone, ImplementFinished},   // terminal
		{StatusCancelled, ImplementStart}, // must reopen first
	}
	for _, tc := range cases {
		t.Run(string(tc.from)+"_"+string(tc.event), func(t *testing.T) {
			_, err := ApplyTransition(tc.from, tc.event)
			assert.Error(t, err)
		})
	}
}

func TestIsUserOnly(t *testing.T) {
	assert.True(t, StartOver.IsUserOnly())
	assert.True(t, Cancel.IsUserOnly())
	assert.True(t, Reopen.IsUserOnly())
	assert.False(t, PlannerFinished.IsUserOnly())
	assert.False(t, ReviewApproved.IsUserOnly())
}

func TestTaskStateMachine_TransitionWritesToStore(t *testing.T) {
	store := taskstore.NewTestSQLiteStore(t)
	dir := t.TempDir()

	// Seed with a ready plan
	ps, err := taskstate.Load(store, "test-proj", dir)
	require.NoError(t, err)
	require.NoError(t, ps.Register("test.md", "test plan", "plan/test", time.Now()))

	fsm := New(store, "test-proj", dir)
	err = fsm.Transition("test.md", PlanStart)
	require.NoError(t, err)

	// Re-read from store to verify persistence
	reloaded, err := taskstate.Load(store, "test-proj", dir)
	require.NoError(t, err)
	entry, ok := reloaded.Entry("test.md")
	require.True(t, ok)
	assert.Equal(t, "planning", string(entry.Status))
}

func TestTaskStateMachine_RejectsInvalidTransition(t *testing.T) {
	store := taskstore.NewTestSQLiteStore(t)
	dir := t.TempDir()

	ps, err := taskstate.Load(store, "test-proj", dir)
	require.NoError(t, err)
	require.NoError(t, ps.Register("test.md", "test plan", "plan/test", time.Now()))

	fsm := New(store, "test-proj", dir)
	err = fsm.Transition("test.md", ImplementFinished) // ready → implement_finished is invalid
	assert.Error(t, err)

	// Status must remain unchanged in store
	reloaded, err := taskstate.Load(store, "test-proj", dir)
	require.NoError(t, err)
	entry, ok := reloaded.Entry("test.md")
	require.True(t, ok)
	assert.Equal(t, "ready", string(entry.Status))
}

func TestTaskStateMachine_MissingPlanReturnsError(t *testing.T) {
	fsm, _ := newTestFSM(t)
	err := fsm.Transition("nonexistent.md", PlanStart)
	assert.Error(t, err)
}

func TestFSM_TransitionWithStore(t *testing.T) {
	store := taskstore.NewTestSQLiteStore(t)
	err := store.Create("test-project", taskstore.TaskEntry{
		Filename: "test.md", Status: "ready",
	})
	require.NoError(t, err)

	fsm := New(store, "test-project", t.TempDir())
	require.NoError(t, fsm.Transition("test.md", PlanStart))

	// Verify the store was updated
	entry, err := store.Get("test-project", "test.md")
	require.NoError(t, err)
	assert.Equal(t, "planning", string(entry.Status))
}

package taskfsm

import (
	"os"
	"path/filepath"
	"strings"
)

// Signal represents a parsed sentinel file from an agent.
type Signal struct {
	Event    Event
	TaskFile string
	Body     string // file contents (e.g. review feedback)
	filePath string // full path for deletion
}

// Key returns a dedup key for this signal (event + plan file).
func (s Signal) Key() string {
	return string(s.Event) + ":" + s.PlanFile
}

// sentinelPrefixes maps filename prefixes to FSM events.
var sentinelPrefixes = []struct {
	prefix string
	event  Event
}{
	{"planner-finished-", PlannerFinished},
	{"implement-finished-", ImplementFinished},
	{"review-approved-", ReviewApproved},
	{"review-changes-", ReviewChangesRequested},
}

// ScanSignals reads the given signals directory and returns parsed signals.
// Ignores invalid files and user-only events. Returns nil if directory missing.
// The caller is responsible for passing the full signals directory path
// (e.g. filepath.Join(repoRoot, ".kasmos", "signals")).
func ScanSignals(signalsDir string) []Signal {
	entries, err := os.ReadDir(signalsDir)
	if err != nil {
		return nil
	}

	var signals []Signal
	for _, entry := range entries {
		if entry.IsDir() || strings.HasPrefix(entry.Name(), ".") {
			continue
		}
		sig, ok := parseSignal(signalsDir, entry.Name())
		if !ok {
			continue
		}
		if sig.Event.IsUserOnly() {
			continue
		}
		signals = append(signals, sig)
	}
	return signals
}

// ConsumeSignal deletes the sentinel file after processing.
func ConsumeSignal(sig Signal) {
	_ = os.Remove(sig.filePath)
}

func parseSignal(dir, filename string) (Signal, bool) {
	for _, sp := range sentinelPrefixes {
		if strings.HasPrefix(filename, sp.prefix) {
			planFile := strings.TrimPrefix(filename, sp.prefix)
			if planFile == "" {
				return Signal{}, false
			}
			// Defensive: strip any path prefix (e.g. "docs/plans/") so the
			// planFile matches plan-state.json keys which are bare filenames.
			planFile = filepath.Base(planFile)
			filePath := filepath.Join(dir, filename)
			body := ""
			if data, err := os.ReadFile(filePath); err == nil && len(data) > 0 {
				body = strings.TrimSpace(string(data))
			}
			return Signal{
				Event:    sp.event,
				TaskFile: planFile,
				Body:     body,
				filePath: filePath,
			}, true
		}
	}
	return Signal{}, false
}

package taskfsm

import (
	"os"
	"path/filepath"
	"regexp"
	"strconv"
	"strings"
)

// WaveSignal represents a parsed implement-wave signal file.
type WaveSignal struct {
	WaveNumber int
	PlanFile   string
	filePath   string // full path for deletion
}

var waveSignalRe = regexp.MustCompile(`^implement-wave-(\d+)-(.+\.md)$`)

// ParseWaveSignal attempts to parse a filename as a wave signal.
func ParseWaveSignal(filename string) (WaveSignal, bool) {
	m := waveSignalRe.FindStringSubmatch(filename)
	if m == nil {
		return WaveSignal{}, false
	}
	wave, err := strconv.Atoi(m[1])
	if err != nil {
		return WaveSignal{}, false
	}
	return WaveSignal{
		WaveNumber: wave,
		TaskFile:   m[2],
	}, true
}

// ScanWaveSignals reads the given signals directory and returns parsed wave signals.
// These are handled separately from FSM signals because they don't map to
// state transitions — they trigger wave orchestration in the TUI.
// The caller is responsible for passing the full signals directory path
// (e.g. filepath.Join(repoRoot, ".kasmos", "signals")).
func ScanWaveSignals(signalsDir string) []WaveSignal {
	entries, err := os.ReadDir(signalsDir)
	if err != nil {
		return nil
	}

	var signals []WaveSignal
	for _, entry := range entries {
		if entry.IsDir() || strings.HasPrefix(entry.Name(), ".") {
			continue
		}
		ws, ok := ParseWaveSignal(entry.Name())
		if !ok {
			continue
		}
		ws.filePath = filepath.Join(signalsDir, entry.Name())
		signals = append(signals, ws)
	}
	return signals
}

// ConsumeWaveSignal deletes the wave signal file after processing.
func ConsumeWaveSignal(ws WaveSignal) {
	_ = os.Remove(ws.filePath)
}

package taskfsm

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestParseWaveSignal(t *testing.T) {
	tests := []struct {
		name     string
		filename string
		wantOK   bool
		wantWave int
		wantPlan string
	}{
		{
			name:     "valid wave 1 signal",
			filename: "implement-wave-1-test-plan.md",
			wantOK:   true,
			wantWave: 1,
			wantPlan: "test-plan.md",
		},
		{
			name:     "valid wave 3 signal",
			filename: "implement-wave-3-multi-wave.md",
			wantOK:   true,
			wantWave: 3,
			wantPlan: "multi-wave.md",
		},
		{
			name:     "not a wave signal",
			filename: "planner-finished-test-plan.md",
			wantOK:   false,
		},
		{
			name:     "malformed wave number",
			filename: "implement-wave-abc-test-plan.md",
			wantOK:   false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ws, ok := ParseWaveSignal(tt.filename)
			assert.Equal(t, tt.wantOK, ok)
			if ok {
				assert.Equal(t, tt.wantWave, ws.WaveNumber)
				assert.Equal(t, tt.wantPlan, ws.TaskFile)
			}
		})
	}
}

func TestScanSignals_IncludesWaveSignals(t *testing.T) {
	signalsDir := filepath.Join(t.TempDir(), ".kasmos", "signals")
	require.NoError(t, os.MkdirAll(signalsDir, 0o755))

	// Write a regular signal and a wave signal
	require.NoError(t, os.WriteFile(
		filepath.Join(signalsDir, "planner-finished-test.md"), nil, 0o644))
	require.NoError(t, os.WriteFile(
		filepath.Join(signalsDir, "implement-wave-2-test.md"), nil, 0o644))

	signals := ScanSignals(signalsDir)
	// Regular signal should be present
	assert.Len(t, signals, 1, "only regular signals returned by ScanSignals")

	// Wave signals have their own scanner
	waveSignals := ScanWaveSignals(signalsDir)
	require.Len(t, waveSignals, 1)
	assert.Equal(t, 2, waveSignals[0].WaveNumber)
	assert.Equal(t, "test.md", waveSignals[0].PlanFile)
}

// Package planparser extracts wave/task structure from plan markdown files.
package taskparser

import (
	"fmt"
	"regexp"
	"strconv"
	"strings"
)

// Task represents a single task extracted from a plan.
type Task struct {
	Number int    // Task number (1-indexed, from ### Task N: Title)
	Title  string // Task title (text after "Task N: ")
	Body   string // Full task body (everything between this ### Task and the next heading)
}

// Wave represents a group of tasks that can run in parallel.
type Wave struct {
	Number int    // Wave number (1-indexed)
	Tasks  []Task // Tasks in this wave
}

// Plan represents a parsed plan with header metadata and wave-grouped tasks.
type Plan struct {
	Goal         string
	Architecture string
	TechStack    string
	Waves        []Wave
}

// HeaderContext returns the plan header as a string suitable for task prompts.
func (p *Plan) HeaderContext() string {
	var sb strings.Builder
	if p.Goal != "" {
		sb.WriteString("**Goal:** " + p.Goal + "\n")
	}
	if p.Architecture != "" {
		sb.WriteString("**Architecture:** " + p.Architecture + "\n")
	}
	if p.TechStack != "" {
		sb.WriteString("**Tech Stack:** " + p.TechStack + "\n")
	}
	return sb.String()
}

var (
	waveHeaderRe = regexp.MustCompile(`(?m)^## Wave (\d+)\b.*$`)
	taskHeaderRe = regexp.MustCompile(`(?m)^### Task (\d+):\s*(.+)$`)
	goalRe       = regexp.MustCompile(`(?m)^\*\*Goal:\*\*\s*(.+)$`)
	archRe       = regexp.MustCompile(`(?m)^\*\*Architecture:\*\*\s*(.+)$`)
	techRe       = regexp.MustCompile(`(?m)^\*\*Tech Stack:\*\*\s*(.+)$`)
)

// Parse extracts waves and tasks from plan markdown content.
// Returns an error if no ## Wave headers are found.
func Parse(content string) (*Plan, error) {
	if strings.TrimSpace(content) == "" {
		return nil, fmt.Errorf("empty plan content")
	}

	plan := &Plan{}

	// Extract header fields
	if m := goalRe.FindStringSubmatch(content); len(m) > 1 {
		plan.Goal = strings.TrimSpace(m[1])
	}
	if m := archRe.FindStringSubmatch(content); len(m) > 1 {
		plan.Architecture = strings.TrimSpace(m[1])
	}
	if m := techRe.FindStringSubmatch(content); len(m) > 1 {
		plan.TechStack = strings.TrimSpace(m[1])
	}

	// Find all wave header positions
	waveMatches := waveHeaderRe.FindAllStringSubmatchIndex(content, -1)
	if len(waveMatches) == 0 {
		return nil, fmt.Errorf("no wave headers found in plan; add ## Wave N sections before implementing")
	}

	// Split content into wave sections
	for i, wm := range waveMatches {
		waveNumStr := content[wm[2]:wm[3]]
		waveNum, _ := strconv.Atoi(waveNumStr)

		// Determine the section boundaries for this wave
		sectionStart := wm[1] // end of "## Wave N" line
		var sectionEnd int
		if i+1 < len(waveMatches) {
			sectionEnd = waveMatches[i+1][0] // start of next wave header
		} else {
			sectionEnd = len(content)
		}
		section := content[sectionStart:sectionEnd]

		// Extract tasks from this wave section
		tasks, err := parseTasks(section)
		if err != nil {
			return nil, fmt.Errorf("wave %d: %w", waveNum, err)
		}

		plan.Waves = append(plan.Waves, Wave{
			Number: waveNum,
			Tasks:  tasks,
		})
	}

	return plan, nil
}

// parseTasks extracts ### Task entries from a wave section.
func parseTasks(section string) ([]Task, error) {
	taskMatches := taskHeaderRe.FindAllStringSubmatchIndex(section, -1)
	if len(taskMatches) == 0 {
		return nil, nil
	}

	var tasks []Task
	for i, tm := range taskMatches {
		numStr := section[tm[2]:tm[3]]
		num, _ := strconv.Atoi(numStr)
		title := strings.TrimSpace(section[tm[4]:tm[5]])

		// Task body: from end of header line to start of next task (or end of section)
		bodyStart := tm[1]
		var bodyEnd int
		if i+1 < len(taskMatches) {
			bodyEnd = taskMatches[i+1][0]
		} else {
			bodyEnd = len(section)
		}
		body := strings.TrimSpace(section[bodyStart:bodyEnd])

		tasks = append(tasks, Task{
			Number: num,
			Title:  title,
			Body:   body,
		})
	}

	return tasks, nil
}

package taskstate

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/kastheco/kasmos/config/taskstore"
)

type Status string

const (
	StatusReady     Status = "ready"
	StatusDone      Status = "done"
	StatusReviewing Status = "reviewing"
	StatusCancelled Status = "cancelled"

	// Lifecycle-stage statuses — canonical names used by the FSM.
	StatusPlanning     Status = "planning"
	StatusImplementing Status = "implementing"
)

type TaskEntry struct {
	Status        Status    `json:"status"`
	Description   string    `json:"description,omitempty"`
	Branch        string    `json:"branch,omitempty"`
	Topic         string    `json:"topic,omitempty"`
	CreatedAt     time.Time `json:"created_at,omitempty"`
	Implemented   string    `json:"implemented,omitempty"`
	ClickUpTaskID string    `json:"clickup_task_id,omitempty"`
	ReviewCycle   int       `json:"review_cycle,omitempty"`
}

type TopicEntry struct {
	CreatedAt time.Time `json:"created_at"`
}

type TaskState struct {
	Dir          string
	Plans        map[string]TaskEntry
	TopicEntries map[string]TopicEntry
	store        taskstore.Store // always non-nil
	project      string          // project name used with the store
}

type TaskInfo struct {
	Filename    string
	Status      Status
	Description string
	Branch      string
	Topic       string
	CreatedAt   time.Time
}

type TopicInfo struct {
	Name      string
	CreatedAt time.Time
}

// Load creates a TaskState backed by the given store. Plans and TopicEntries are
// populated from the store. dir is retained for file operations (e.g. Rename moves
// the .md file on disk). The store is always required — there is no JSON fallback.
func Load(store taskstore.Store, project, dir string) (*TaskState, error) {
	plans, err := store.List(project)
	if err != nil {
		return nil, fmt.Errorf("plan store: %w", err)
	}

	topics, err := store.ListTopics(project)
	if err != nil {
		return nil, fmt.Errorf("plan store: %w", err)
	}

	ps := &TaskState{
		Dir:          dir,
		Plans:        make(map[string]TaskEntry, len(plans)),
		TopicEntries: make(map[string]TopicEntry, len(topics)),
		store:        store,
		project:      project,
	}

	for _, e := range plans {
		ps.Plans[e.Filename] = TaskEntry{
			Status:        Status(e.Status),
			Description:   e.Description,
			Branch:        e.Branch,
			Topic:         e.Topic,
			CreatedAt:     e.CreatedAt,
			Implemented:   e.Implemented,
			ClickUpTaskID: e.ClickUpTaskID,
			ReviewCycle:   e.ReviewCycle,
		}
	}

	for _, t := range topics {
		ps.TopicEntries[t.Name] = TopicEntry{CreatedAt: t.CreatedAt}
	}

	return ps, nil
}

// Topics returns all topic entries sorted by name.
func (ps *TaskState) Topics() []TopicInfo {
	// Discover topics from both TopicEntries and plan topic fields.
	seen := make(map[string]TopicInfo)
	for name, entry := range ps.TopicEntries {
		seen[name] = TopicInfo{Name: name, CreatedAt: entry.CreatedAt}
	}
	for _, entry := range ps.Plans {
		if entry.Topic != "" {
			if _, ok := seen[entry.Topic]; !ok {
				seen[entry.Topic] = TopicInfo{Name: entry.Topic}
			}
		}
	}
	result := make([]TopicInfo, 0, len(seen))
	for _, info := range seen {
		result = append(result, info)
	}
	sort.Slice(result, func(i, j int) bool {
		return result[i].Name < result[j].Name
	})
	return result
}

// TasksByTopic returns all plans in the given topic, sorted by filename.
func (ps *TaskState) TasksByTopic(topic string) []TaskInfo {
	result := make([]TaskInfo, 0)
	for filename, entry := range ps.Plans {
		if entry.Topic == topic {
			result = append(result, TaskInfo{
				Filename: filename, Status: entry.Status,
				Description: entry.Description, Branch: entry.Branch,
				Topic: entry.Topic, CreatedAt: entry.CreatedAt,
			})
		}
	}
	sort.Slice(result, func(i, j int) bool {
		return result[i].Filename < result[j].Filename
	})
	return result
}

// UngroupedTasks returns all active plans with no topic, sorted by filename.
func (ps *TaskState) UngroupedTasks() []TaskInfo {
	result := make([]TaskInfo, 0)
	for filename, entry := range ps.Plans {
		if entry.Status == StatusDone || entry.Status == StatusCancelled {
			continue
		}
		if entry.Topic == "" {
			result = append(result, TaskInfo{
				Filename: filename, Status: entry.Status,
				Description: entry.Description, Branch: entry.Branch,
				CreatedAt: entry.CreatedAt,
			})
		}
	}
	sort.Slice(result, func(i, j int) bool {
		return result[i].Filename < result[j].Filename
	})
	return result
}

// hasTopicEntry returns true if the given topic name exists in TopicEntries.
func (ps *TaskState) hasTopicEntry(topic string) bool {
	if ps.TopicEntries == nil {
		return false
	}
	_, exists := ps.TopicEntries[topic]
	return exists
}

// HasRunningCoderInTopic checks if any plan in the given topic (other than
// excludePlan) has status StatusImplementing. Returns the conflicting plan filename.
func (ps *TaskState) HasRunningCoderInTopic(topic, excludePlan string) (bool, string) {
	if topic == "" {
		return false, ""
	}
	for filename, entry := range ps.Plans {
		if filename == excludePlan {
			continue
		}
		if entry.Topic == topic && entry.Status == StatusImplementing {
			return true, filename
		}
	}
	return false, ""
}

// Unfinished returns plans that are not done or cancelled, sorted by filename.
func (ps *TaskState) Unfinished() []TaskInfo {
	result := make([]TaskInfo, 0, len(ps.Plans))
	for filename, entry := range ps.Plans {
		if entry.Status == StatusDone || entry.Status == StatusCancelled {
			continue
		}
		result = append(result, TaskInfo{
			Filename: filename, Status: entry.Status,
			Description: entry.Description, Branch: entry.Branch,
			Topic: entry.Topic, CreatedAt: entry.CreatedAt,
		})
	}
	sort.Slice(result, func(i, j int) bool {
		return result[i].Filename < result[j].Filename
	})
	return result
}

// Finished returns plans that are done, sorted by creation time (newest first).
func (ps *TaskState) Finished() []TaskInfo {
	result := make([]TaskInfo, 0)
	for filename, entry := range ps.Plans {
		if entry.Status != StatusDone {
			continue
		}
		result = append(result, TaskInfo{
			Filename: filename, Status: entry.Status,
			Description: entry.Description, Branch: entry.Branch,
			Topic: entry.Topic, CreatedAt: entry.CreatedAt,
		})
	}
	sort.Slice(result, func(i, j int) bool {
		if !result[i].CreatedAt.Equal(result[j].CreatedAt) {
			return result[i].CreatedAt.After(result[j].CreatedAt)
		}
		return result[i].Filename > result[j].Filename
	})
	return result
}

// Cancelled returns all cancelled plans, sorted by filename.
func (ps *TaskState) Cancelled() []TaskInfo {
	result := make([]TaskInfo, 0)
	for filename, entry := range ps.Plans {
		if entry.Status != StatusCancelled {
			continue
		}
		result = append(result, TaskInfo{
			Filename: filename, Status: entry.Status,
			Description: entry.Description, Branch: entry.Branch,
			Topic: entry.Topic, CreatedAt: entry.CreatedAt,
		})
	}
	sort.Slice(result, func(i, j int) bool {
		return result[i].Filename < result[j].Filename
	})
	return result
}

// List returns all plans (including done and cancelled), sorted by filename.
func (ps *TaskState) List() []TaskInfo {
	result := make([]TaskInfo, 0, len(ps.Plans))
	for filename, entry := range ps.Plans {
		result = append(result, TaskInfo{
			Filename:    filename,
			Status:      entry.Status,
			Description: entry.Description,
			Branch:      entry.Branch,
			Topic:       entry.Topic,
			CreatedAt:   entry.CreatedAt,
		})
	}
	sort.Slice(result, func(i, j int) bool {
		return result[i].Filename < result[j].Filename
	})
	return result
}

// IsDone returns true only if the given plan has status StatusDone.
func (ps *TaskState) IsDone(filename string) bool {
	entry, ok := ps.Plans[filename]
	if !ok {
		return false
	}
	return entry.Status == StatusDone
}

// ForceSetStatus overrides a plan's status regardless of FSM rules.
// Validates the status is a known value. Use only for manual overrides (e.g. kq plan set-status --force).
func (ps *TaskState) ForceSetStatus(filename string, status Status) error {
	if !isValidStatus(status) {
		return fmt.Errorf("invalid status %q: must be one of ready, planning, implementing, reviewing, done, cancelled", status)
	}
	if _, ok := ps.Plans[filename]; !ok {
		return fmt.Errorf("plan not found: %s", filename)
	}
	entry := ps.Plans[filename]
	entry.Status = status
	ps.Plans[filename] = entry
	if err := ps.store.Update(ps.project, filename, ps.toTaskstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	return nil
}

// isValidStatus returns true if s is a recognised lifecycle status.
func isValidStatus(s Status) bool {
	switch s {
	case StatusReady, StatusPlanning, StatusImplementing, StatusReviewing, StatusDone, StatusCancelled:
		return true
	}
	return false
}

// setStatus updates a plan's status and persists to the store.
// Unexported: only for use within this package (tests). Production code must use taskfsm.Transition.
func (ps *TaskState) setStatus(filename string, status Status) error {
	if ps.Plans == nil {
		ps.Plans = make(map[string]TaskEntry)
	}
	entry := ps.Plans[filename]
	entry.Status = status
	ps.Plans[filename] = entry
	if err := ps.store.Update(ps.project, filename, ps.toTaskstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	return nil
}

// CreateWithContent adds a new plan entry with markdown content stored in the backend.
// The plan entry is created with StatusReady, and the content is persisted via store.SetContent.
// Returns an error if the plan already exists.
func (ps *TaskState) CreateWithContent(filename, description, branch, topic string, createdAt time.Time, content string) error {
	if err := ps.Create(filename, description, branch, topic, createdAt); err != nil {
		return err
	}
	if err := ps.store.SetContent(ps.project, filename, content); err != nil {
		return fmt.Errorf("plan store set content: %w", err)
	}
	return nil
}

// GetContent retrieves the markdown content for the given plan filename from the store.
func (ps *TaskState) GetContent(filename string) (string, error) {
	return ps.store.GetContent(ps.project, filename)
}

// SetContent updates the markdown content for the given plan filename in the store.
func (ps *TaskState) SetContent(filename, content string) error {
	return ps.store.SetContent(ps.project, filename, content)
}

// Create adds a new plan entry to the state and auto-creates the topic if needed.
func (ps *TaskState) Create(filename, description, branch, topic string, createdAt time.Time) error {
	if ps.Plans == nil {
		ps.Plans = make(map[string]TaskEntry)
	}
	if _, exists := ps.Plans[filename]; exists {
		return fmt.Errorf("plan already exists: %s", filename)
	}
	entry := TaskEntry{
		Status:      StatusReady,
		Description: description,
		Branch:      branch,
		Topic:       topic,
		CreatedAt:   createdAt.UTC(),
	}
	ps.Plans[filename] = entry
	// Auto-create topic entry if it doesn't exist
	if topic != "" {
		if ps.TopicEntries == nil {
			ps.TopicEntries = make(map[string]TopicEntry)
		}
		if _, exists := ps.TopicEntries[topic]; !exists {
			ps.TopicEntries[topic] = TopicEntry{CreatedAt: createdAt.UTC()}
		}
	}
	if err := ps.store.Create(ps.project, ps.toTaskstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	// Auto-create topic in store if needed
	if topic != "" {
		topicEntry := taskstore.TopicEntry{Name: topic, CreatedAt: createdAt.UTC()}
		if err := ps.store.CreateTopic(ps.project, topicEntry); err != nil {
			// Ignore "already exists" errors for topics
			if !isAlreadyExistsError(err) {
				return fmt.Errorf("plan store: %w", err)
			}
		}
	}
	return nil
}

// Register adds a new plan entry with metadata and persists to the store.
// Returns an error if the plan already exists.
func (ps *TaskState) Register(filename, description, branch string, createdAt time.Time) error {
	if ps.Plans == nil {
		ps.Plans = make(map[string]TaskEntry)
	}
	if _, exists := ps.Plans[filename]; exists {
		return fmt.Errorf("plan already exists: %s", filename)
	}
	entry := TaskEntry{
		Status:      StatusReady,
		Description: description,
		Branch:      branch,
		CreatedAt:   createdAt.UTC(),
	}
	ps.Plans[filename] = entry
	if err := ps.store.Create(ps.project, ps.toTaskstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	return nil
}

// Entry returns the TaskEntry for the given filename, and whether it exists.
func (ps *TaskState) Entry(filename string) (TaskEntry, bool) {
	entry, ok := ps.Plans[filename]
	return entry, ok
}

// SetTopic assigns a topic to an existing plan entry and persists to the store.
// If topic is non-empty and does not yet exist in TopicEntries, it is auto-created.
// Pass an empty string to remove the plan from any topic.
func (ps *TaskState) SetTopic(filename, topic string) error {
	entry, ok := ps.Plans[filename]
	if !ok {
		return fmt.Errorf("plan not found: %s", filename)
	}
	entry.Topic = topic
	ps.Plans[filename] = entry
	// Auto-create topic entry if it doesn't exist
	if topic != "" {
		if ps.TopicEntries == nil {
			ps.TopicEntries = make(map[string]TopicEntry)
		}
		if _, exists := ps.TopicEntries[topic]; !exists {
			ps.TopicEntries[topic] = TopicEntry{CreatedAt: time.Now().UTC()}
		}
	}
	if err := ps.store.Update(ps.project, filename, ps.toTaskstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	// Auto-create topic in store if needed
	if topic != "" {
		topicEntry := taskstore.TopicEntry{Name: topic, CreatedAt: ps.TopicEntries[topic].CreatedAt}
		if err := ps.store.CreateTopic(ps.project, topicEntry); err != nil {
			if !isAlreadyExistsError(err) {
				return fmt.Errorf("plan store: %w", err)
			}
		}
	}
	return nil
}

// SetBranch assigns a branch name to an existing plan entry and persists to the store.
func (ps *TaskState) SetBranch(filename, branch string) error {
	entry, ok := ps.Plans[filename]
	if !ok {
		return fmt.Errorf("plan not found: %s", filename)
	}
	entry.Branch = branch
	ps.Plans[filename] = entry
	if err := ps.store.Update(ps.project, filename, ps.toTaskstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	return nil
}

// Save is a no-op — all mutations write through to the store immediately.
// Retained for API compatibility.
func (ps *TaskState) Save() error {
	return nil
}

// DisplayName strips the .md extension from a plan filename.
// "auth-refactor.md" → "auth-refactor"
func DisplayName(filename string) string {
	return strings.TrimSuffix(filename, ".md")
}

// Rename renames a plan by giving it a new display name slug.
// It renames the .md file on disk (if it exists), rekeys the planstate entry,
// and persists the updated state.
// newName should be a human-readable name (e.g., "auth refactor") which will be
// slugified automatically. Returns the new filename on success.
func (ps *TaskState) Rename(oldFilename, newName string) (string, error) {
	entry, ok := ps.Plans[oldFilename]
	if !ok {
		return "", fmt.Errorf("plan not found: %s", oldFilename)
	}
	if newName == "" {
		return "", fmt.Errorf("new name cannot be empty")
	}

	// Build new filename from the slug alone.
	newSlug := slugify(newName)
	if newSlug == "" {
		return "", fmt.Errorf("new name produced an empty slug")
	}
	newFilename := newSlug + ".md"

	if newFilename == oldFilename {
		return oldFilename, nil // nothing to do
	}
	if _, exists := ps.Plans[newFilename]; exists {
		return "", fmt.Errorf("a plan named %q already exists", newFilename)
	}

	// Rename file on disk if it exists.
	oldPath := filepath.Join(ps.Dir, oldFilename)
	newPath := filepath.Join(ps.Dir, newFilename)
	if _, err := os.Stat(oldPath); err == nil {
		if err := os.Rename(oldPath, newPath); err != nil {
			return "", fmt.Errorf("rename plan file: %w", err)
		}
	}

	// Rekey the planstate entry.
	ps.Plans[newFilename] = entry
	delete(ps.Plans, oldFilename)

	if err := ps.store.Rename(ps.project, oldFilename, newFilename); err != nil {
		return "", fmt.Errorf("plan store: %w", err)
	}
	return newFilename, nil
}

// slugify converts a human name to a lowercase, hyphen-separated slug.
// "My Cool Feature!" → "my-cool-feature"
func slugify(name string) string {
	name = strings.ToLower(strings.TrimSpace(name))
	// Replace any sequence of non-alphanumeric characters with a hyphen.
	result := make([]rune, 0, len(name))
	inHyphen := false
	for _, r := range name {
		if r >= 'a' && r <= 'z' || r >= '0' && r <= '9' {
			result = append(result, r)
			inHyphen = false
		} else if !inHyphen && len(result) > 0 {
			result = append(result, '-')
			inHyphen = true
		}
	}
	// Trim trailing hyphen.
	for len(result) > 0 && result[len(result)-1] == '-' {
		result = result[:len(result)-1]
	}
	return string(result)
}

// isAlreadyExistsError returns true if the error indicates a duplicate resource.
func isAlreadyExistsError(err error) bool {
	if err == nil {
		return false
	}
	msg := err.Error()
	return strings.Contains(msg, "already exists")
}

// toTaskstoreEntry converts a local TaskEntry to a taskstore.TaskEntry for
// writing to the store.
func (ps *TaskState) toTaskstoreEntry(filename string, e TaskEntry) taskstore.TaskEntry {
	return taskstore.TaskEntry{
		Filename:      filename,
		Status:        taskstore.Status(e.Status),
		Description:   e.Description,
		Branch:        e.Branch,
		Topic:         e.Topic,
		CreatedAt:     e.CreatedAt,
		Implemented:   e.Implemented,
		ClickUpTaskID: e.ClickUpTaskID,
		ReviewCycle:   e.ReviewCycle,
	}
}

// SetClickUpTaskID assigns a ClickUp task ID to an existing plan entry and
// persists to the store.
func (ps *TaskState) SetClickUpTaskID(filename, taskID string) error {
	entry, ok := ps.Plans[filename]
	if !ok {
		return fmt.Errorf("plan not found: %s", filename)
	}
	entry.ClickUpTaskID = taskID
	ps.Plans[filename] = entry
	if err := ps.store.SetClickUpTaskID(ps.project, filename, taskID); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	return nil
}

// ReviewCycle returns the current review cycle counter for the given plan.
// Returns an error if the plan is not found.
func (ps *TaskState) ReviewCycle(filename string) (int, error) {
	entry, ok := ps.Plans[filename]
	if !ok {
		return 0, fmt.Errorf("plan not found: %s", filename)
	}
	return entry.ReviewCycle, nil
}

// IncrementReviewCycle increments the review cycle counter for the given plan
// and persists to the store. Updates the in-memory state to reflect the new value.
// Returns an error if the plan is not found.
func (ps *TaskState) IncrementReviewCycle(filename string) error {
	entry, ok := ps.Plans[filename]
	if !ok {
		return fmt.Errorf("plan not found: %s", filename)
	}
	if err := ps.store.IncrementReviewCycle(ps.project, filename); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	entry.ReviewCycle++
	ps.Plans[filename] = entry
	return nil
}

