	defer srv.Close()

	client := taskstore.NewHTTPStore(srv.URL, "kasmos")
	require.NoError(t, client.Ping())
}

package taskstore

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"
)

// jsonTaskEntry is the on-disk format for a single plan in plan-state.json.
type jsonTaskEntry struct {
	Status      string `json:"status"`
	Description string `json:"description,omitempty"`
	Branch      string `json:"branch,omitempty"`
	Topic       string `json:"topic,omitempty"`
	CreatedAt   string `json:"created_at,omitempty"`
	Implemented string `json:"implemented,omitempty"`
}

// jsonTopicEntry is the on-disk format for a single topic in plan-state.json.
type jsonTopicEntry struct {
	CreatedAt string `json:"created_at"`
}

// jsonTaskState is the top-level structure of plan-state.json.
type jsonTaskState struct {
	Plans  map[string]jsonTaskEntry  `json:"plans"`
	Topics map[string]jsonTopicEntry `json:"topics"`
}

// MigrateFromJSON reads plan-state.json from plansDir and imports all plans
// and topics into the store under the given project. If plan-state.json does
// not exist, it returns (0, nil) — a no-op. The migration is idempotent:
// plans and topics that already exist in the store are silently skipped.
// For each plan entry that has a corresponding .md file in plansDir, the file
// content is also imported via SetContent.
//
// Returns the number of plans successfully migrated (newly created).
func MigrateFromJSON(store Store, project, plansDir string) (int, error) {
	stateFile := filepath.Join(plansDir, "plan-state.json")

	data, err := os.ReadFile(stateFile)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return 0, nil
		}
		return 0, fmt.Errorf("read plan-state.json: %w", err)
	}

	var state jsonTaskState
	if err := json.Unmarshal(data, &state); err != nil {
		return 0, fmt.Errorf("parse plan-state.json: %w", err)
	}

	migrated := 0

	// Migrate plans.
	for filename, jp := range state.Plans {
		entry := TaskEntry{
			Filename:    filename,
			Status:      Status(jp.Status),
			Description: jp.Description,
			Branch:      jp.Branch,
			Topic:       jp.Topic,
			Implemented: jp.Implemented,
		}
		if jp.CreatedAt != "" {
			entry.CreatedAt = parseTime(jp.CreatedAt)
		}

		if err := store.Create(project, entry); err != nil {
			// Skip if already exists (idempotent).
			if strings.Contains(err.Error(), "plan already exists") {
				continue
			}
			return migrated, fmt.Errorf("migrate plan %s: %w", filename, err)
		}
		migrated++

		// Import .md file content if it exists on disk.
		mdPath := filepath.Join(plansDir, filename)
		content, err := os.ReadFile(mdPath)
		if err != nil {
			if !errors.Is(err, os.ErrNotExist) {
				return migrated, fmt.Errorf("read plan content %s: %w", filename, err)
			}
			// No .md file — that's fine, content stays empty.
		} else {
			if err := store.SetContent(project, filename, string(content)); err != nil {
				return migrated, fmt.Errorf("set content for %s: %w", filename, err)
			}
		}
	}

	// Migrate topics.
	for name, jt := range state.Topics {
		var createdAt time.Time
		if jt.CreatedAt != "" {
			createdAt = parseTime(jt.CreatedAt)
		}
		entry := TopicEntry{
			Name:      name,
			CreatedAt: createdAt,
		}
		if err := store.CreateTopic(project, entry); err != nil {
			// Skip if already exists (idempotent).
			if strings.Contains(err.Error(), "topic already exists") {
				continue
			}
			return migrated, fmt.Errorf("migrate topic %s: %w", name, err)
		}
	}

	return migrated, nil
}

package taskstore

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestMigrateFromJSON(t *testing.T) {
	store := newTestStore(t)
	plansDir := t.TempDir()

	stateJSON := `{
        "plans": {
            "test.md": {
                "status": "ready",
                "description": "test plan",
                "branch": "plan/test"
            }
        },
        "topics": {
            "tools": {"created_at": "2026-02-28T00:00:00Z"}
        }
    }`
	require.NoError(t, os.WriteFile(filepath.Join(plansDir, "plan-state.json"), []byte(stateJSON), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(plansDir, "test.md"), []byte("# Test Plan"), 0o644))

	migrated, err := MigrateFromJSON(store, "proj", plansDir)
	require.NoError(t, err)
	assert.Equal(t, 1, migrated)

	entry, err := store.Get("proj", "test.md")
	require.NoError(t, err)
	assert.Equal(t, StatusReady, entry.Status)
	assert.Equal(t, "test plan", entry.Description)

	content, err := store.GetContent("proj", "test.md")
	require.NoError(t, err)
	assert.Equal(t, "# Test Plan", content)

	topics, err := store.ListTopics("proj")
	require.NoError(t, err)
	assert.Len(t, topics, 1)
}

func TestMigrateFromJSON_Idempotent(t *testing.T) {
	store := newTestStore(t)
	plansDir := t.TempDir()

	stateJSON := `{"plans": {"test.md": {"status": "done"}}}`
	require.NoError(t, os.WriteFile(filepath.Join(plansDir, "plan-state.json"), []byte(stateJSON), 0o644))

	_, err := MigrateFromJSON(store, "proj", plansDir)
	require.NoError(t, err)

	_, err = MigrateFromJSON(store, "proj", plansDir)
	require.NoError(t, err) // second run should not error
}

func TestMigrateFromJSON_NoFile(t *testing.T) {
	store := newTestStore(t)
	migrated, err := MigrateFromJSON(store, "proj", t.TempDir())
	require.NoError(t, err)
	assert.Equal(t, 0, migrated)
}

package taskstore

import (
	"encoding/json"
	"io"
	"net/http"
	"strings"
)

// NewHandler returns an http.Handler that exposes the Store over HTTP.
// It uses Go 1.22+ ServeMux pattern matching for method+path routing.
func NewHandler(store Store) http.Handler {
	mux := http.NewServeMux()

	// Health check
	mux.HandleFunc("GET /v1/ping", func(w http.ResponseWriter, r *http.Request) {
		if err := store.Ping(); err != nil {
			writeError(w, http.StatusServiceUnavailable, err.Error())
			return
		}
		w.WriteHeader(http.StatusOK)
	})

	// List plans (with optional ?status= and ?topic= filters)
	mux.HandleFunc("GET /v1/projects/{project}/plans", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		statusFilters := r.URL.Query()["status"]
		topicFilter := r.URL.Query().Get("topic")

		var (
			plans []TaskEntry
			err   error
		)
		switch {
		case topicFilter != "":
			plans, err = store.ListByTopic(project, topicFilter)
		case len(statusFilters) > 0:
			statuses := make([]Status, len(statusFilters))
			for i, s := range statusFilters {
				statuses[i] = Status(s)
			}
			plans, err = store.ListByStatus(project, statuses...)
		default:
			plans, err = store.List(project)
		}
		if err != nil {
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		writeJSON(w, http.StatusOK, plans)
	})

	// Create plan
	mux.HandleFunc("POST /v1/projects/{project}/plans", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		var entry TaskEntry
		if err := json.NewDecoder(r.Body).Decode(&entry); err != nil {
			writeError(w, http.StatusBadRequest, "invalid request body: "+err.Error())
			return
		}
		if err := store.Create(project, entry); err != nil {
			writeError(w, http.StatusConflict, err.Error())
			return
		}
		writeJSON(w, http.StatusCreated, entry)
	})

	// Get plan
	mux.HandleFunc("GET /v1/projects/{project}/plans/{filename}", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		entry, err := store.Get(project, filename)
		if err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		writeJSON(w, http.StatusOK, entry)
	})

	// Update plan
	mux.HandleFunc("PUT /v1/projects/{project}/plans/{filename}", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		var entry TaskEntry
		if err := json.NewDecoder(r.Body).Decode(&entry); err != nil {
			writeError(w, http.StatusBadRequest, "invalid request body: "+err.Error())
			return
		}
		if err := store.Update(project, filename, entry); err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		writeJSON(w, http.StatusOK, entry)
	})

	// Get plan content
	mux.HandleFunc("GET /v1/projects/{project}/plans/{filename}/content", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		content, err := store.GetContent(project, filename)
		if err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		w.Header().Set("Content-Type", "text/markdown")
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(content))
	})

	// Set plan content
	mux.HandleFunc("PUT /v1/projects/{project}/plans/{filename}/content", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		body, err := io.ReadAll(r.Body)
		if err != nil {
			writeError(w, http.StatusBadRequest, "failed to read request body: "+err.Error())
			return
		}
		if err := store.SetContent(project, filename, string(body)); err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		w.WriteHeader(http.StatusOK)
	})

	// Set ClickUp task ID
	mux.HandleFunc("PUT /v1/projects/{project}/plans/{filename}/clickup-task-id", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		var req struct {
			ClickUpTaskID string `json:"clickup_task_id"`
		}
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			writeError(w, http.StatusBadRequest, "invalid request body: "+err.Error())
			return
		}
		if err := store.SetClickUpTaskID(project, filename, req.ClickUpTaskID); err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		w.WriteHeader(http.StatusOK)
	})

	// Increment review cycle
	mux.HandleFunc("POST /v1/projects/{project}/plans/{filename}/increment-review-cycle", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		if err := store.IncrementReviewCycle(project, filename); err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		w.WriteHeader(http.StatusOK)
	})

	// Rename plan
	mux.HandleFunc("POST /v1/projects/{project}/plans/{filename}/rename", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		filename := r.PathValue("filename")
		var req struct {
			NewFilename string `json:"new_filename"`
		}
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			writeError(w, http.StatusBadRequest, "invalid request body: "+err.Error())
			return
		}
		if req.NewFilename == "" {
			writeError(w, http.StatusBadRequest, "new_filename is required")
			return
		}
		if err := store.Rename(project, filename, req.NewFilename); err != nil {
			if isNotFound(err) {
				writeError(w, http.StatusNotFound, "plan not found: "+filename)
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		w.WriteHeader(http.StatusOK)
	})

	// List topics
	mux.HandleFunc("GET /v1/projects/{project}/topics", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		topics, err := store.ListTopics(project)
		if err != nil {
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		writeJSON(w, http.StatusOK, topics)
	})

	// Create topic
	mux.HandleFunc("POST /v1/projects/{project}/topics", func(w http.ResponseWriter, r *http.Request) {
		project := r.PathValue("project")
		var entry TopicEntry
		if err := json.NewDecoder(r.Body).Decode(&entry); err != nil {
			writeError(w, http.StatusBadRequest, "invalid request body: "+err.Error())
			return
		}
		if err := store.CreateTopic(project, entry); err != nil {
			writeError(w, http.StatusConflict, err.Error())
			return
		}
		writeJSON(w, http.StatusCreated, entry)
	})

	return mux
}

// writeJSON encodes v as JSON and writes it to w with the given status code.
func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	json.NewEncoder(w).Encode(v)
}

// writeError writes a JSON error response with the given status code and message.
func writeError(w http.ResponseWriter, status int, msg string) {
	writeJSON(w, status, map[string]string{"error": msg})
}

// isNotFound returns true if the error indicates a missing resource.
// Store implementations return errors containing "not found" for missing plans.
func isNotFound(err error) bool {
	if err == nil {
		return false
	}
	return strings.Contains(err.Error(), "not found")
}

package taskstore

import (
	"database/sql"
	"fmt"
	"strings"
	"time"

	_ "modernc.org/sqlite" // register sqlite driver
)

const schema = `
CREATE TABLE IF NOT EXISTS plans (
	id          INTEGER PRIMARY KEY,
	project     TEXT    NOT NULL,
	filename    TEXT    NOT NULL,
	status      TEXT    NOT NULL DEFAULT 'ready',
	description TEXT    NOT NULL DEFAULT '',
	branch      TEXT    NOT NULL DEFAULT '',
	topic       TEXT    NOT NULL DEFAULT '',
	created_at  TEXT    NOT NULL DEFAULT '',
	implemented TEXT    NOT NULL DEFAULT '',
	UNIQUE(project, filename)
);

CREATE TABLE IF NOT EXISTS topics (
	id         INTEGER PRIMARY KEY,
	project    TEXT NOT NULL,
	name       TEXT NOT NULL,
	created_at TEXT NOT NULL DEFAULT '',
	UNIQUE(project, name)
);
`

// contentMigration adds the content column to existing databases that predate it.
const contentMigration = `ALTER TABLE plans ADD COLUMN content TEXT NOT NULL DEFAULT ''`

// clickupTaskIDMigration adds the clickup_task_id column to existing databases.
const clickupTaskIDMigration = `ALTER TABLE plans ADD COLUMN clickup_task_id TEXT NOT NULL DEFAULT ''`

// reviewCycleMigration adds the review_cycle column to existing databases.
const reviewCycleMigration = `ALTER TABLE plans ADD COLUMN review_cycle INTEGER NOT NULL DEFAULT 0`

// SQLiteStore is a Store implementation backed by a SQLite database.
type SQLiteStore struct {
	db *sql.DB
}

// NewSQLiteStore opens (or creates) a SQLite database at dbPath and runs
// schema migrations. Use ":memory:" for an in-memory database (useful in tests).
func NewSQLiteStore(dbPath string) (*SQLiteStore, error) {
	db, err := sql.Open("sqlite", dbPath)
	if err != nil {
		return nil, fmt.Errorf("open sqlite db: %w", err)
	}

	// Enable WAL mode for better concurrent read performance.
	if dbPath != ":memory:" {
		if _, err := db.Exec("PRAGMA journal_mode=WAL"); err != nil {
			db.Close()
			return nil, fmt.Errorf("set WAL mode: %w", err)
		}
	}

	// Enable foreign keys.
	if _, err := db.Exec("PRAGMA foreign_keys=ON"); err != nil {
		db.Close()
		return nil, fmt.Errorf("enable foreign keys: %w", err)
	}

	if _, err := db.Exec(schema); err != nil {
		db.Close()
		return nil, fmt.Errorf("run schema migrations: %w", err)
	}

	// Add content column if it doesn't exist (upgrade existing databases).
	if err := migrateAddContentColumn(db); err != nil {
		db.Close()
		return nil, fmt.Errorf("migrate content column: %w", err)
	}

	// Add clickup_task_id column if it doesn't exist (upgrade existing databases).
	if err := migrateAddColumn(db, "clickup_task_id", clickupTaskIDMigration); err != nil {
		db.Close()
		return nil, fmt.Errorf("migrate clickup_task_id column: %w", err)
	}

	// Add review_cycle column if it doesn't exist (upgrade existing databases).
	if err := migrateAddColumn(db, "review_cycle", reviewCycleMigration); err != nil {
		db.Close()
		return nil, fmt.Errorf("migrate review_cycle column: %w", err)
	}

	return &SQLiteStore{db: db}, nil
}

// migrateAddContentColumn adds the content column to the plans table if it
// doesn't already exist. This upgrades databases created before the column
// was introduced.
func migrateAddContentColumn(db *sql.DB) error {
	return migrateAddColumn(db, "content", contentMigration)
}

// migrateAddColumn adds a column to the plans table if it doesn't already
// exist, running the provided ALTER TABLE statement when needed.
func migrateAddColumn(db *sql.DB, columnName, alterSQL string) error {
	rows, err := db.Query("PRAGMA table_info(plans)")
	if err != nil {
		return fmt.Errorf("query table info: %w", err)
	}
	defer rows.Close()

	for rows.Next() {
		var cid int
		var name, colType string
		var notNull int
		var dfltValue sql.NullString
		var pk int
		if err := rows.Scan(&cid, &name, &colType, &notNull, &dfltValue, &pk); err != nil {
			return fmt.Errorf("scan table info: %w", err)
		}
		if name == columnName {
			return nil // column already exists
		}
	}
	if err := rows.Err(); err != nil {
		return fmt.Errorf("iterate table info: %w", err)
	}

	// Column doesn't exist — add it.
	if _, err := db.Exec(alterSQL); err != nil {
		return fmt.Errorf("add %s column: %w", columnName, err)
	}
	return nil
}

// Close releases the database connection.
func (s *SQLiteStore) Close() error {
	return s.db.Close()
}

// Ping verifies the database connection is alive.
func (s *SQLiteStore) Ping() error {
	return s.db.Ping()
}

// Create inserts a new plan entry for the given project.
// Returns an error if a plan with the same filename already exists in the project.
func (s *SQLiteStore) Create(project string, entry TaskEntry) error {
	const q = `
		INSERT INTO plans (project, filename, status, description, branch, topic, created_at, implemented, content, clickup_task_id, review_cycle)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
	`
	_, err := s.db.Exec(q,
		project,
		entry.Filename,
		string(entry.Status),
		entry.Description,
		entry.Branch,
		entry.Topic,
		formatTime(entry.CreatedAt),
		entry.Implemented,
		entry.Content,
		entry.ClickUpTaskID,
		entry.ReviewCycle,
	)
	if err != nil {
		if isUniqueConstraintError(err) {
			return fmt.Errorf("plan already exists: %s/%s", project, entry.Filename)
		}
		return fmt.Errorf("create plan: %w", err)
	}
	return nil
}

// Get retrieves a plan entry by project and filename.
// Returns an error if the plan is not found.
func (s *SQLiteStore) Get(project, filename string) (TaskEntry, error) {
	const q = `
		SELECT filename, status, description, branch, topic, created_at, implemented, content, clickup_task_id, review_cycle
		FROM plans
		WHERE project = ? AND filename = ?
	`
	row := s.db.QueryRow(q, project, filename)
	return scanTaskEntry(row)
}

// Update replaces all fields of an existing plan entry.
// Returns an error if the plan is not found.
func (s *SQLiteStore) Update(project, filename string, entry TaskEntry) error {
	const q = `
		UPDATE plans
		SET status = ?, description = ?, branch = ?, topic = ?, created_at = ?, implemented = ?, content = ?, clickup_task_id = ?, review_cycle = ?
		WHERE project = ? AND filename = ?
	`
	result, err := s.db.Exec(q,
		string(entry.Status),
		entry.Description,
		entry.Branch,
		entry.Topic,
		formatTime(entry.CreatedAt),
		entry.Implemented,
		entry.Content,
		entry.ClickUpTaskID,
		entry.ReviewCycle,
		project,
		filename,
	)
	if err != nil {
		return fmt.Errorf("update plan: %w", err)
	}
	n, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("update plan rows affected: %w", err)
	}
	if n == 0 {
		return fmt.Errorf("plan not found: %s/%s", project, filename)
	}
	return nil
}

// Rename changes the filename of an existing plan entry.
// Returns an error if the old filename is not found or the new filename already exists.
func (s *SQLiteStore) Rename(project, oldFilename, newFilename string) error {
	const q = `
		UPDATE plans
		SET filename = ?
		WHERE project = ? AND filename = ?
	`
	result, err := s.db.Exec(q, newFilename, project, oldFilename)
	if err != nil {
		if isUniqueConstraintError(err) {
			return fmt.Errorf("plan already exists: %s/%s", project, newFilename)
		}
		return fmt.Errorf("rename plan: %w", err)
	}
	n, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("rename plan rows affected: %w", err)
	}
	if n == 0 {
		return fmt.Errorf("plan not found: %s/%s", project, oldFilename)
	}
	return nil
}

// List returns all plan entries for the given project, sorted by filename.
func (s *SQLiteStore) List(project string) ([]TaskEntry, error) {
	const q = `
		SELECT filename, status, description, branch, topic, created_at, implemented, content, clickup_task_id, review_cycle
		FROM plans
		WHERE project = ?
		ORDER BY filename ASC
	`
	rows, err := s.db.Query(q, project)
	if err != nil {
		return nil, fmt.Errorf("list plans: %w", err)
	}
	defer rows.Close()
	return scanTaskEntries(rows)
}

// ListByStatus returns all plan entries for the given project matching any of
// the provided statuses, sorted by filename.
func (s *SQLiteStore) ListByStatus(project string, statuses ...Status) ([]TaskEntry, error) {
	if len(statuses) == 0 {
		return nil, nil
	}

	placeholders := make([]string, len(statuses))
	args := make([]any, 0, len(statuses)+1)
	args = append(args, project)
	for i, s := range statuses {
		placeholders[i] = "?"
		args = append(args, string(s))
	}

	q := fmt.Sprintf(`
		SELECT filename, status, description, branch, topic, created_at, implemented, content, clickup_task_id, review_cycle
		FROM plans
		WHERE project = ? AND status IN (%s)
		ORDER BY filename ASC
	`, strings.Join(placeholders, ", "))

	rows, err := s.db.Query(q, args...)
	if err != nil {
		return nil, fmt.Errorf("list plans by status: %w", err)
	}
	defer rows.Close()
	return scanTaskEntries(rows)
}

// ListByTopic returns all plan entries for the given project and topic,
// sorted by filename.
func (s *SQLiteStore) ListByTopic(project, topic string) ([]TaskEntry, error) {
	const q = `
		SELECT filename, status, description, branch, topic, created_at, implemented, content, clickup_task_id, review_cycle
		FROM plans
		WHERE project = ? AND topic = ?
		ORDER BY filename ASC
	`
	rows, err := s.db.Query(q, project, topic)
	if err != nil {
		return nil, fmt.Errorf("list plans by topic: %w", err)
	}
	defer rows.Close()
	return scanTaskEntries(rows)
}

// ListTopics returns all topic entries for the given project, sorted by name.
func (s *SQLiteStore) ListTopics(project string) ([]TopicEntry, error) {
	const q = `
		SELECT name, created_at
		FROM topics
		WHERE project = ?
		ORDER BY name ASC
	`
	rows, err := s.db.Query(q, project)
	if err != nil {
		return nil, fmt.Errorf("list topics: %w", err)
	}
	defer rows.Close()

	var topics []TopicEntry
	for rows.Next() {
		var name, createdAt string
		if err := rows.Scan(&name, &createdAt); err != nil {
			return nil, fmt.Errorf("scan topic: %w", err)
		}
		topics = append(topics, TopicEntry{
			Name:      name,
			CreatedAt: parseTime(createdAt),
		})
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate topics: %w", err)
	}
	return topics, nil
}

// CreateTopic inserts a new topic entry for the given project.
// Returns an error if a topic with the same name already exists in the project.
func (s *SQLiteStore) CreateTopic(project string, entry TopicEntry) error {
	const q = `
		INSERT INTO topics (project, name, created_at)
		VALUES (?, ?, ?)
	`
	_, err := s.db.Exec(q, project, entry.Name, formatTime(entry.CreatedAt))
	if err != nil {
		if isUniqueConstraintError(err) {
			return fmt.Errorf("topic already exists: %s/%s", project, entry.Name)
		}
		return fmt.Errorf("create topic: %w", err)
	}
	return nil
}

// GetContent retrieves only the content field for a plan entry.
// Returns an error if the plan is not found.
func (s *SQLiteStore) GetContent(project, filename string) (string, error) {
	const q = `SELECT content FROM plans WHERE project = ? AND filename = ?`
	var content string
	err := s.db.QueryRow(q, project, filename).Scan(&content)
	if err != nil {
		if err == sql.ErrNoRows {
			return "", fmt.Errorf("plan not found: %s/%s", project, filename)
		}
		return "", fmt.Errorf("get content: %w", err)
	}
	return content, nil
}

// SetContent updates only the content field for an existing plan entry.
// Returns an error if the plan is not found.
func (s *SQLiteStore) SetContent(project, filename, content string) error {
	const q = `UPDATE plans SET content = ? WHERE project = ? AND filename = ?`
	result, err := s.db.Exec(q, content, project, filename)
	if err != nil {
		return fmt.Errorf("set content: %w", err)
	}
	n, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("set content rows affected: %w", err)
	}
	if n == 0 {
		return fmt.Errorf("plan not found: %s/%s", project, filename)
	}
	return nil
}

// SetClickUpTaskID sets the ClickUp task ID for an existing plan entry.
// Returns an error if the plan is not found.
func (s *SQLiteStore) SetClickUpTaskID(project, filename, taskID string) error {
	const q = `UPDATE plans SET clickup_task_id = ? WHERE project = ? AND filename = ?`
	result, err := s.db.Exec(q, taskID, project, filename)
	if err != nil {
		return fmt.Errorf("set clickup_task_id: %w", err)
	}
	n, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("set clickup_task_id rows affected: %w", err)
	}
	if n == 0 {
		return fmt.Errorf("plan not found: %s/%s", project, filename)
	}
	return nil
}

// IncrementReviewCycle atomically increments the review_cycle counter for an existing plan entry.
// Returns an error if the plan is not found.
func (s *SQLiteStore) IncrementReviewCycle(project, filename string) error {
	const q = `UPDATE plans SET review_cycle = review_cycle + 1 WHERE project = ? AND filename = ?`
	result, err := s.db.Exec(q, project, filename)
	if err != nil {
		return fmt.Errorf("increment review_cycle: %w", err)
	}
	n, err := result.RowsAffected()
	if err != nil {
		return fmt.Errorf("increment review_cycle rows affected: %w", err)
	}
	if n == 0 {
		return fmt.Errorf("plan not found: %s/%s", project, filename)
	}
	return nil
}

// scanTaskEntry scans a single row into a TaskEntry.
func scanTaskEntry(row *sql.Row) (TaskEntry, error) {
	var filename, status, description, branch, topic, createdAt, implemented, content, clickupTaskID string
	var reviewCycle int
	if err := row.Scan(&filename, &status, &description, &branch, &topic, &createdAt, &implemented, &content, &clickupTaskID, &reviewCycle); err != nil {
		if err == sql.ErrNoRows {
			return TaskEntry{}, fmt.Errorf("plan not found")
		}
		return TaskEntry{}, fmt.Errorf("scan plan: %w", err)
	}
	return TaskEntry{
		Filename:      filename,
		Status:        Status(status),
		Description:   description,
		Branch:        branch,
		Topic:         topic,
		CreatedAt:     parseTime(createdAt),
		Implemented:   implemented,
		Content:       content,
		ClickUpTaskID: clickupTaskID,
		ReviewCycle:   reviewCycle,
	}, nil
}

// scanTaskEntries scans multiple rows into a slice of TaskEntry.
func scanTaskEntries(rows *sql.Rows) ([]TaskEntry, error) {
	var entries []TaskEntry
	for rows.Next() {
		var filename, status, description, branch, topic, createdAt, implemented, content, clickupTaskID string
		var reviewCycle int
		if err := rows.Scan(&filename, &status, &description, &branch, &topic, &createdAt, &implemented, &content, &clickupTaskID, &reviewCycle); err != nil {
			return nil, fmt.Errorf("scan plan: %w", err)
		}
		entries = append(entries, TaskEntry{
			Filename:      filename,
			Status:        Status(status),
			Description:   description,
			Branch:        branch,
			Topic:         topic,
			CreatedAt:     parseTime(createdAt),
			Implemented:   implemented,
			Content:       content,
			ClickUpTaskID: clickupTaskID,
			ReviewCycle:   reviewCycle,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate plans: %w", err)
	}
	return entries, nil
}

// formatTime formats a time.Time as RFC3339 for storage. Zero time returns empty string.
func formatTime(t time.Time) string {
	if t.IsZero() {
		return ""
	}
	return t.UTC().Format(time.RFC3339Nano)
}

// parseTime parses an RFC3339 string. Returns zero time on empty or invalid input.
func parseTime(s string) time.Time {
	if s == "" {
		return time.Time{}
	}
	t, err := time.Parse(time.RFC3339Nano, s)
	if err != nil {
		return time.Time{}
	}
	return t
}

// isUniqueConstraintError returns true if the error is a SQLite UNIQUE constraint violation.
func isUniqueConstraintError(err error) bool {
	if err == nil {
		return false
	}
	return strings.Contains(err.Error(), "UNIQUE constraint failed")
}

// Package planstore provides a Store interface for plan state persistence,
// with a SQLite implementation for direct DB access and an HTTP implementation
// for client-server communication.
package taskstore

import "time"

// Status represents the lifecycle state of a plan.
// These constants mirror taskstate.Status to keep planstore self-contained
// and avoid circular imports.
type Status string

const (
	StatusReady        Status = "ready"
	StatusDone         Status = "done"
	StatusReviewing    Status = "reviewing"
	StatusCancelled    Status = "cancelled"
	StatusPlanning     Status = "planning"
	StatusImplementing Status = "implementing"
)

// TaskEntry holds the persisted metadata for a single plan.
type TaskEntry struct {
	Filename      string    `json:"filename"`
	Status        Status    `json:"status"`
	Description   string    `json:"description,omitempty"`
	Branch        string    `json:"branch,omitempty"`
	Topic         string    `json:"topic,omitempty"`
	CreatedAt     time.Time `json:"created_at,omitempty"`
	Implemented   string    `json:"implemented,omitempty"`
	Content       string    `json:"content,omitempty"`
	ClickUpTaskID string    `json:"clickup_task_id,omitempty"`
	ReviewCycle   int       `json:"review_cycle,omitempty"`
}

// TopicEntry holds the persisted metadata for a topic grouping.
type TopicEntry struct {
	Name      string    `json:"name"`
	CreatedAt time.Time `json:"created_at"`
}

// Store is the interface for plan state persistence. Implementations include
// SQLiteStore (direct DB access, used by the server) and HTTPStore (client
// that talks to the server over HTTP).
type Store interface {
	// Plan CRUD
	Create(project string, entry TaskEntry) error
	Get(project, filename string) (TaskEntry, error)
	Update(project, filename string, entry TaskEntry) error
	Rename(project, oldFilename, newFilename string) error

	// Content access
	GetContent(project, filename string) (string, error)
	SetContent(project, filename, content string) error

	// ClickUp integration
	SetClickUpTaskID(project, filename, taskID string) error

	// Review cycle
	IncrementReviewCycle(project, filename string) error

	// Queries
	List(project string) ([]TaskEntry, error)
	ListByStatus(project string, statuses ...Status) ([]TaskEntry, error)
	ListByTopic(project, topic string) ([]TaskEntry, error)

	// Topics
	ListTopics(project string) ([]TopicEntry, error)
	CreateTopic(project string, entry TopicEntry) error

	// Health
	Ping() error

	// Close releases any resources held by the store.
	Close() error
}

